      } else {
        this._flush();
      }
    });

    this._writeStream.on('close', () => {
      this._writeStream = null;
      this.emit('write_close');
    });
  }

  _flush() {
    if (!this._queue.size || this._waitForDrain) return;
    this._writeStream.cork();
    for (const [key, cbs] of this._queue) {
      this._queue.delete(key);
